class ImbalancedDataSampler:
    def __init__(self, class_balance):
        self.class_balance = class_balance

    def sample(self, X, y):
        if self.class_balance == 'minority':
            return self.sample_minority(X, y)
        elif self.class_balance == 'majority':
            return self.sample_majority(X, y)
        else:
            raise ValueError("Invalid class balance")

    def sample_minority(self, X, y):
        # SMOTE with a probability of 0.5
        from imblearn.over_sampling import SMOTE
        smote = SMOTE(random_state=42)
        X_res, y_res = smote.fit_resample(X, y)
        return X_res, y_res

    def sample_majority(self, X, y):
        # RandomOverSampler with a ratio of 0.5
        from imblearn.over_sampling import RandomOverSampler
        ros = RandomOverSampler(random_state=42)
        X_res, y_res = ros.fit_resample(X, y)
        return X_res, y_res
